<template>
    <div class="d-flex justify-content-center align-items-center h-100">
        <b-card title="Welcome to Trivialize!" sub-title="Click the button below to connect your account and get started" v-if="!$store.state.accessToken">
            <b-button @click="redirectToSpotify" style="color: green; background-color: black" size="lg"><i class="fab fa-spotify"></i></b-button>
        </b-card>
        <b-card title="Waiting For Spotify Device" v-else>
            <b-spinner label="Spinning" />
        </b-card>

        <TheWebPlayback></TheWebPlayback>

        <b-modal title="Trivialize Lite" ok-only v-model="isPlayliteModalOpen" size="lg" class="text-left" @ok="$router.push('/play')">
            <h1 class="text-center">Before you Play...</h1>
            <h6>
                We noticed your Spotify account is a free version. You'll still be able to take advantage of most of Trivialize's features, but
                this means you won't be able to link up a Spotify device to Trivialize.
            </h6>
            <h6>
                Because of this, the songs that are played are from Spotify's 30 second previews clips.
                This can mean that all songs in your playlists aren't available (if Spotify doesn't have a preview available) and tracks won't be played at random times (They
                won't start at the beginning, but they will always begin at the same spot)
            </h6>
            <h6>You're still welcome to use the rest of the features Trivialize has to offer. Have fun!</h6>
        </b-modal>
    </div>
</template>

<script>
    import {spotifyAuthUrl} from "@/spotifyAppConfig";
    import TheWebPlayback from "@/components/TheNavbar/TheWebPlayback";
    import SpotifyController from '@/SpotifyController'

    export default {
        name: 'home',
        components: {TheWebPlayback},
        data() {
            return {
                isPlayliteModalOpen: false
            }
        },
        created() {
            // Get token sent by Spotify in URL
            if (window.location.hash) {
                this.getTokenFromURL();
            }
        },
        methods: {
            async getTokenFromURL() {
                let hash = window.location.hash.substring(1);
                let token = hash.split('=')[1];
                this.$store.commit('updateAccessToken', token);
                let r = await new SpotifyController(this.$store.state.accessToken).getUserProfile();
                if (r.data.product === 'premium') {
                    this.$store.commit('updateIsPremium', true);
                    this.$store.commit('updateInfoModalOpen', true);
                }
                else {
                    this.isPlayliteModalOpen = true;
                }
                // NOTE: The redirect to choose playlist is done by TheWebPlayback state

            },
            redirectToSpotify() {
                window.location.href = spotifyAuthUrl;
            },
        },
    }
</script>
